grid.expression:
/* PARTE 1: Busca apenas se EXISTIREM restrições especiais */ SELECT O.OPCAO, I.TIPRESTRICAO, UFORIG.UF AS UFORIG, UFDEST.UF AS UFDEST, I.CODRESTRICAO, I.CODTRIB, I.ALIQUOTA, I.REDBASE, I.MVASTUFDEST, I.MARGLUCROEST, I.CSOSN FROM TGFICM I JOIN TDDCAM C ON C.NOMETAB = 'TGFICM' AND C.NOMECAMPO = 'TIPRESTRICAO' JOIN TDDOPC O ON O.NUCAMPO = C.NUCAMPO AND O.VALOR = I.TIPRESTRICAO JOIN TSIUFS UFORIG ON UFORIG.CODUF = I.UFORIG JOIN TSIUFS UFDEST ON UFDEST.CODUF = I.UFDEST WHERE I.TIPRESTRICAO NOT IN ('S','X', 'N')
UNION ALL
/* PARTE 2: Exibe a mensagem APENAS se não existir nenhuma restrição especial na tabela */ SELECT 'Todas as operações analisadas são tributadas integralmente, sendo assim as regras da base modelo atendem o cliente' AS OPCAO, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL FROM DUAL -- Ou (SELECT 1) em alguns bancos WHERE NOT EXISTS ( SELECT 1 FROM TGFICM WHERE TIPRESTRICAO NOT IN ('S','X', 'N') )
ORDER BY CODRESTRICAO
